import sailpoint.object.Identity;
import sailpoint.object.Filter;

Identity identity=null;
if(formModel!=null @and formModel.get("primaryAccount")!=null){
log.error("fetching identity in workflow Request CreateADAdminAccount step.....  :");
String identityId=formModel.get("primaryAccount");
Filter filter=Filter.and((Filter.or(Filter.eq("name",identityId),Filter.eq("id",identityId))),Filter.eq("type","employee"));
identity=context.getUniqueObject(Identity.class,filter);
}else{
throw new Exception("formModel primaryAccount value is null...");
}

return identity;

import sailpoint.object.Identity;
import sailpoint.object.Filter;

log.error("formModel in secondaryIdType arg in workflow Request CreateADAdminAccount step....."+formModel);
String secondaryIdType;
if(formModel!=null){
log.error("fetching secondaryIdType in workflow Request CreateADAdminAccount step.....  :");
secondaryIdType=formModel.get("secondaryIdType");
}else{
throw new Exception("formModel secondaryIdType value is null...");
}
return secondaryIdType;

import sailpoint.api.Provisioner;

log.error("plan variable in provisioner execution---"+account_plan.toXml());
Provisioner provisioner=new Provisioner(context);
provisioner.setNoCreateTemplates(true);
return provisioner.execute(account_plan);
